import { test, expect } from "./helpers";

const GCODE = [
  "; generated by e2e",
  "; estimated printing time (normal mode) = 30m 12s",
  "; filament used [g] = 6.8",
  "G28",
  "G1 Z0.2 F300",
  "G1 X10 Y10 E1 F1200",
].join("\n");

function modelCard(page: import("@playwright/test").Page, name: string) {
  return page.locator('a[href^="/models/"]').filter({ hasText: name });
}

// Full lifecycle on the REAL backend: upload G-code → real ingestion creates the
// model → edit it → soft-delete to trash → restore → purge forever.
test("upload, edit, trash, restore, and purge a model", async ({ page }) => {
  const name = `e2e-model-${Date.now()}`;
  const renamed = `${name}-renamed`;

  // ── Upload ────────────────────────────────────────────────────────────────
  await page.goto("/");
  await page.getByRole("button", { name: "Upload" }).click();
  await expect(page.getByRole("dialog", { name: "Upload model" })).toBeVisible();
  await page.locator('input[accept=".gcode,.g,.gco"]').setInputFiles({
    name: "part.gcode",
    mimeType: "text/plain",
    buffer: Buffer.from(GCODE),
  });
  await page.getByPlaceholder("e.g. Bracket v2").fill(name);
  await page.getByRole("button", { name: /upload to vault/i }).click();
  await expect(page.getByRole("dialog", { name: "Upload model" })).toHaveCount(0);

  // Ingestion is async on the real backend — poll the library until it lands.
  await expect(async () => {
    await page.goto("/");
    await expect(modelCard(page, name)).toBeVisible({ timeout: 2_000 });
  }).toPass({ timeout: 30_000 });

  // ── Edit ──────────────────────────────────────────────────────────────────
  await modelCard(page, name).click();
  await expect(page.getByRole("heading", { name })).toBeVisible();
  await page.getByRole("button", { name: /^Edit$/ }).click();
  const nameInput = page.getByPlaceholder("Model name");
  await nameInput.fill(renamed);
  await page.getByRole("button", { name: /^Save$/ }).click();
  await expect(page.getByRole("heading", { name: renamed })).toBeVisible();

  // ── Soft-delete to trash ────────────────────────────────────────────────────
  await page.getByRole("button", { name: /^Delete$/ }).click();
  await page.getByRole("dialog").getByRole("button", { name: "Delete" }).click(); // confirm
  await expect(modelCard(page, renamed)).toHaveCount(0);

  // ── Restore from Settings → Trash ───────────────────────────────────────────
  await page.goto("/settings");
  await page.getByRole("button", { name: "Trash" }).click();
  await expect(page.getByText(renamed)).toBeVisible();
  await page.getByRole("button", { name: "Restore" }).click();
  await expect(page.getByText(renamed)).toHaveCount(0); // gone from trash

  // Back in the library.
  await expect(async () => {
    await page.goto("/");
    await expect(modelCard(page, renamed)).toBeVisible({ timeout: 2_000 });
  }).toPass({ timeout: 15_000 });

  // ── Delete + purge forever (cleanup) ────────────────────────────────────────
  await modelCard(page, renamed).click();
  await page.getByRole("button", { name: /^Delete$/ }).click();
  await page.getByRole("dialog").getByRole("button", { name: "Delete" }).click();
  await page.goto("/settings");
  await page.getByRole("button", { name: "Trash" }).click();
  await expect(page.getByText(renamed)).toBeVisible();
  await page.getByRole("button", { name: "Delete", exact: true }).click();
  await page.getByRole("button", { name: "Delete forever" }).click();
  await expect(page.getByText(renamed)).toHaveCount(0);
});
